import * as React from "react";
import { useState, useEffect, useMemo } from "react";
import { makeStyles, Input, Spinner, TabList, Tab, Text, Card, Tooltip, Button, Title3 } from "@fluentui/react-components";
import { Search24Regular } from "@fluentui/react-icons";

const useStyles = makeStyles({
  root: {
    padding: "16px",
    display: "flex",
    flexDirection: "column",
    gap: "16px",
    minHeight: "100vh",
    boxSizing: "border-box"
  },
  header: {
    display: "flex",
    flexDirection: "column",
    gap: "8px"
  },
  searchBox: {
    width: "100%"
  },
  iconGrid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fill, minmax(48px, 1fr))",
    gap: "12px",
    marginTop: "16px"
  },
  iconCard: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "8px",
    cursor: "pointer",
    borderRadius: "4px",
    "&:hover": {
      backgroundColor: "#f3f2f1"
    }
  },
  iconImg: {
    width: "32px",
    height: "32px",
    objectFit: "contain"
  },
  divider: {
    gridColumn: "1 / -1",
    paddingTop: "16px",
    paddingBottom: "8px",
    borderBottom: "1px solid #edebe9",
    marginBottom: "8px",
    fontWeight: "bold",
    color: "#605e5c"
  },
  toast: {
    position: "fixed",
    bottom: "20px",
    left: "50%",
    transform: "translateX(-50%)",
    backgroundColor: "#323130",
    color: "white",
    padding: "12px 24px",
    borderRadius: "4px",
    zIndex: 1000,
    boxShadow: "0 4px 8px rgba(0,0,0,0.2)",
    opacity: 0,
    transition: "opacity 0.3s ease-in-out",
    pointerEvents: "none"
  },
  toastVisible: {
    opacity: 1
  }
});

const SYNONYM_CLUSTERS = [
    ["add", "plus", "create", "new", "insert", "append", "positive", "increase", "include"],
    ["delete", "trash", "remove", "bin", "garbage", "minus", "cancel", "clear", "drop", "reduce", "decrease"],
    ["edit", "pencil", "pen", "write", "update", "change", "modify", "rename"],
    ["search", "magnifying", "glass", "find", "zoom", "explore", "discover", "look"],
    ["settings", "gear", "cog", "preferences", "options", "config", "setup", "control", "adjust", "slider"],
    ["user", "person", "profile", "account", "human", "avatar", "member", "people"],
    ["home", "house", "main", "dashboard", "start"],
    ["upload", "arrow up", "arrow-up", "cloud up", "export", "send", "push", "publish"],
    ["download", "arrow down", "arrow-down", "cloud down", "import", "receive", "pull", "save"],
    ["save", "floppy", "disk", "store", "keep", "bookmark", "archive"],
    ["refresh", "reload", "sync", "update", "circle arrow", "restart"],
    ["close", "x", "cross", "exit", "quit", "cancel"],
    ["success", "check", "tick", "done", "complete", "approved", "verify", "yes"],
    ["warning", "alert", "triangle", "exclamation", "caution", "danger", "attention", "error"],
    ["error", "x", "cross", "fail", "invalid", "alert", "danger", "no", "warning"],
    ["fast", "lightning", "bolt", "quick", "speed", "flash", "rocket", "performance"],
    ["slow", "turtle", "snail", "hourglass", "wait", "time"],
    ["secure", "lock", "shield", "safe", "protect", "privacy", "security", "auth"],
    ["unsecure", "unlock", "open", "insecure"],
    ["visible", "eye", "show", "view", "watch", "reveal", "public", "display"],
    ["hidden", "eye off", "hide", "blind", "invisible", "conceal", "private"],
    ["love", "heart", "favorite", "like", "adore", "save"],
    ["copy", "duplicate", "clone", "files", "clipboard", "replicate"],
    ["link", "chain", "url", "connect", "attach", "hyperlink", "anchor"],
    ["picture", "image", "photo", "gallery", "photography", "camera", "visual"],
    ["video", "movie", "film", "camera", "play", "cinema", "media"],
    ["message", "chat", "bubble", "sms", "text", "conversation", "talk", "communicate"],
    ["mail", "envelope", "email", "letter", "inbox", "send", "receive"],
    ["call", "phone", "telephone", "ring", "contact", "dial", "mobile"],
    ["time", "clock", "watch", "hour", "minute", "schedule", "calendar", "date", "event", "history", "recent"],
    ["help", "question", "mark", "support", "info", "faq", "information"],
    ["document", "file", "paper", "page", "sheet", "record", "notes"],
    ["folder", "directory", "archive", "organize"],
    ["share", "network", "distribute", "forward", "publish"],
    ["print", "printer", "fax", "paper"],
    ["cloud", "internet", "network", "online", "server", "hosting"],
    ["location", "pin", "map", "marker", "place", "gps", "navigation", "destination", "pointer"],
    ["shopping", "cart", "basket", "bag", "store", "ecommerce", "buy", "purchase", "checkout"],
    ["payment", "card", "credit", "money", "cash", "wallet", "dollar", "finance", "billing", "price"],
    ["analytics", "chart", "graph", "stats", "statistics", "data", "metrics", "report", "dashboard", "trend", "presentation"],
    ["menu", "hamburger", "list", "navigation", "bars", "lines"],
    ["more", "dots", "ellipsis", "options", "actions", "overflow"]
];

interface IconData {
    file: string;
    label: string;
    tags: string[];
    source?: string;
    svgBase64?: string;
}

interface AppProps {
  title?: string;
}

const App: React.FC<AppProps> = (_props) => {
  const styles = useStyles();
  const [allIcons, setAllIcons] = useState<IconData[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [query, setQuery] = useState<string>("");
  const [sourceFilter, setSourceFilter] = useState<string>("both");
  const [toastVisible, setToastVisible] = useState<boolean>(false);
  const [toastMessage, setToastMessage] = useState<string>("Copied SVG to Clipboard!");

  useEffect(() => {
    fetch(`assets/icons.json?v=${Date.now()}`)
      .then(res => res.json())
      .then(data => {
        setAllIcons(data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }, []);

  const handleInsert = async (icon: IconData) => {
    try {
        const response = await fetch(`assets/icons/${icon.file}`);
        if (!response.ok) throw new Error("Failed to fetch SVG");
        const svgText = await response.text();
        
        // 1. VSTO Hybrid Approach (WebView2)
        if ((window as any).chrome && (window as any).chrome.webview) {
            setToastMessage("✓ Icon added to slide!");
            (window as any).chrome.webview.postMessage(svgText);
            setToastVisible(true);
            setTimeout(() => setToastVisible(false), 2000);
            return;
        }

        // 2. Standard Office Web Add-in Fallback
        if (typeof Office !== 'undefined' && Office.context && Office.context.document) {
            setToastMessage("FALLBACK: Office.js Blocked");
            Office.context.document.setSelectedDataAsync(
                svgText,
                { coercionType: Office.CoercionType.XmlSvg },
                async (asyncResult) => {
                    if (asyncResult.status === Office.AsyncResultStatus.Failed) {
                        console.warn("Direct vector insertion unsupported. Falling back to clipboard.");
                        await navigator.clipboard.writeText(svgText);
                    }
                    setToastVisible(true);
                    setTimeout(() => setToastVisible(false), 2000);
                }
            );
            return;
        }
        
        // 3. Ultimate Fallback (Standard Web Browser)
        setToastMessage("FALLBACK: Standard Browser Clipboard");
        await navigator.clipboard.writeText(svgText);
        setToastVisible(true);
        setTimeout(() => setToastVisible(false), 2000);
        
    } catch (err) {
        setToastMessage("CRASH: " + err);
        setToastVisible(true);
        setTimeout(() => setToastVisible(false), 2000);
        console.error("Failed to fetch or insert", err);
    }
  };

  const filteredIcons = useMemo(() => {
    if (!allIcons.length) return [];

    let filtered = allIcons.filter(icon => {
        if (sourceFilter === 'gep') return !icon.source || icon.source !== 'external';
        if (sourceFilter === 'external') return icon.source === 'external';
        return true;
    });

    const parsedQuery = query.toLowerCase().trim().replace('artificial intelligence', 'ai');
    const searchTerms = parsedQuery.split(/\s+/).filter(t => t.length > 0);

    if (searchTerms.length > 0) {
        let scoredIcons = filtered.map(icon => {
            const labelStr = (icon.label || '').toLowerCase();
            const tagsStr = (icon.tags || []).join(' ').toLowerCase();
            const searchBase = labelStr + " " + tagsStr;
            
            let isMatch = true;
            let score = 0;

            for (const term of searchTerms) {
                let termMatch = false;
                
                let expandedTerms = [term];
                for (const cluster of SYNONYM_CLUSTERS) {
                    if (cluster.some(alias => alias === term || alias.startsWith(term))) {
                        expandedTerms = Array.from(new Set(expandedTerms.concat(cluster)));
                    }
                }

                for (const expTerm of expandedTerms) {
                    if (expTerm === 'ai') {
                        if (/\b(ai|robot|bot|chatbot|chip|microchip|artificial|intelligence|5g|brain)\b/i.test(searchBase)) {
                            termMatch = true;
                            score += 10;
                            break;
                        }
                    } else {
                        if (new RegExp('\\b' + expTerm + '\\b', 'i').test(searchBase)) {
                            termMatch = true;
                            score += 5;
                            break; 
                        } else if (searchBase.includes(expTerm)) {
                            termMatch = true;
                            score += 1;
                            break; 
                        }
                    }
                }

                if (!termMatch) {
                    isMatch = false;
                    break;
                }
            }

            if (isMatch) {
                return { ...icon, _score: score };
            }
            return null;
        }).filter(Boolean) as (IconData & { _score: number })[];

        scoredIcons.sort((a, b) => b._score - a._score);
        return scoredIcons;
    }

    return filtered;
  }, [query, sourceFilter, allIcons]);

  const gepIcons = filteredIcons.filter(i => !i.source || i.source !== 'external');
  const extIcons = filteredIcons.filter(i => i.source === 'external');

  useEffect(() => {
    // Listen for messages from C# WebView2 host
    const handleMessage = async (event: any) => {
        if (!event.data) return;
        
        try {
            let data = event.data;
            if (typeof data === 'string') {
                try { data = JSON.parse(data); } catch { return; }
            }
            
            if (data.action === "matchIconsToTextBoxes") {
                const textBoxes = data.textBoxes || [];
                if (textBoxes.length === 0) {
                    setToastMessage("Please select text boxes first!");
                    setToastVisible(true);
                    setTimeout(() => setToastVisible(false), 3000);
                    return;
                }
                
                const matchedIcons = [];
                let notFoundCount = 0;
                
                for (const tb of textBoxes) {
                    const text = (tb.text || "").toLowerCase().trim();
                    if (!text) continue;
                    
                    const searchTerms = text.split(/\s+/).filter((t: string) => t.length > 0);
                    let bestMatch = null;
                    let highestScore = -1;
                    
                    for (const icon of allIcons) {
                        const labelStr = (icon.label || '').toLowerCase();
                        const tagsStr = (icon.tags || []).join(' ').toLowerCase();
                        const searchBase = labelStr + " " + tagsStr;
                        
                        let isMatch = true;
                        let score = 0;
                        
                        for (const term of searchTerms) {
                            if (new RegExp('\\b' + term + '\\b', 'i').test(searchBase)) {
                                score += 5;
                            } else if (searchBase.includes(term)) {
                                score += 1;
                            } else {
                                isMatch = false;
                                break;
                            }
                        }
                        
                        if (isMatch && score > highestScore) {
                            highestScore = score;
                            bestMatch = icon;
                        }
                    }
                    
                    if (bestMatch) {
                        try {
                            const res = await fetch(`assets/icons/${bestMatch.file}`);
                            const svgText = await res.text();
                            
                            const iconSize = 56.69;
                            const padding = 14;
                            let finalLeft = tb.left - iconSize - padding;
                            if (finalLeft < 0) finalLeft = 0;
                            
                            const finalTop = tb.top + (tb.height - iconSize) / 2;
                            
                            matchedIcons.push({
                                svg: svgText,
                                left: finalLeft,
                                top: finalTop,
                                size: iconSize
                            });
                        } catch (err) {
                            console.error("Failed to fetch icon", err);
                        }
                    } else {
                        notFoundCount++;
                    }
                }
                
                if (matchedIcons.length > 0) {
                    if ((window as any).chrome && (window as any).chrome.webview) {
                        (window as any).chrome.webview.postMessage({
                            action: 'insertMatchedIcons',
                            icons: matchedIcons
                        });
                        
                        if (notFoundCount > 0) {
                            setToastMessage(`Matched ${matchedIcons.length} icons. ${notFoundCount} not found.`);
                        } else {
                            setToastMessage(`Successfully matched ${matchedIcons.length} icons!`);
                        }
                        setToastVisible(true);
                        setTimeout(() => setToastVisible(false), 3000);
                    }
                } else {
                    setToastMessage("No matching icons found for the selected text.");
                    setToastVisible(true);
                    setTimeout(() => setToastVisible(false), 3000);
                }
            }
        } catch (err) {
            console.error("Error processing message from host", err);
        }
    };
    
    window.addEventListener('message', handleMessage);
    if ((window as any).chrome && (window as any).chrome.webview) {
        (window as any).chrome.webview.addEventListener('message', handleMessage);
    }
    
    return () => {
        window.removeEventListener('message', handleMessage);
        if ((window as any).chrome && (window as any).chrome.webview) {
            (window as any).chrome.webview.removeEventListener('message', handleMessage);
        }
    };
  }, [allIcons]);

  if (loading) {
      return (
          <div className={styles.root} style={{ alignItems: "center", justifyContent: "center" }}>
              <Spinner label="Loading icons..." />
          </div>
      );
  }

  return (
    <div className={styles.root}>
      <div className={styles.header}>
        <Title3>GEP Icon Library</Title3>
        <div style={{ marginTop: '10px', marginBottom: '10px' }}>
            <Button 
                appearance="primary" 
                onClick={() => {
                    if ((window as any).chrome && (window as any).chrome.webview) {
                        (window as any).chrome.webview.postMessage(JSON.stringify({ action: 'getSelectedTextBoxes' }));
                    } else {
                        setToastMessage("This feature only works in the PowerPoint Add-in.");
                        setToastVisible(true);
                        setTimeout(() => setToastVisible(false), 3000);
                    }
                }}
            >
                Auto Match Icons
            </Button>
        </div>
      </div>
      
      <TabList selectedValue={sourceFilter} onTabSelect={(_e, data) => setSourceFilter(data.value as string)}>
        <Tab value="both">All</Tab>
        <Tab value="gep">GEP Minimal</Tab>
        <Tab value="external">3rd-Party</Tab>
      </TabList>

      <Input 
        className={styles.searchBox}
        placeholder="Search for action or icon..."
        contentBefore={<Search24Regular />}
        value={query}
        onChange={(_e, data) => setQuery(data.value)}
      />

      <div className={styles.iconGrid}>
          {sourceFilter === 'both' ? (
              <>
                  {gepIcons.map((icon, i) => (
                      <Tooltip key={`gep-${i}`} content={icon.label || icon.tags[0]} relationship="label">
                          <Card className={styles.iconCard} onClick={() => handleInsert(icon)}>
                              <img src={`assets/icons/${icon.file}`} className={styles.iconImg} alt={icon.label} />
                          </Card>
                      </Tooltip>
                  ))}
                  
                  {extIcons.length > 0 && gepIcons.length > 0 && (
                      <div className={styles.divider}>External / 3rd-Party</div>
                  )}

                  {extIcons.map((icon, i) => (
                      <Tooltip key={`ext-${i}`} content={icon.label || icon.tags[0]} relationship="label">
                          <Card className={styles.iconCard} onClick={() => handleInsert(icon)}>
                              <img src={`assets/icons/${icon.file}`} className={styles.iconImg} alt={icon.label} />
                          </Card>
                      </Tooltip>
                  ))}
              </>
          ) : (
              filteredIcons.map((icon, i) => (
                  <Tooltip key={i} content={icon.label || icon.tags[0]} relationship="label">
                      <Card className={styles.iconCard} onClick={() => handleInsert(icon)}>
                          <img src={`assets/icons/${icon.file}`} className={styles.iconImg} alt={icon.label} />
                      </Card>
                  </Tooltip>
              ))
          )}
      </div>

      <div className={`${styles.toast} ${toastVisible ? styles.toastVisible : ""}`}>
        {toastMessage}
      </div>
    </div>
  );
};

export default App;
